parameters.query:
DO $$
DECLARE
  target_phone text := '{{ $('SET telefone').last().json.telefone }}';
BEGIN
  -- Step 1: Delete from user_session
  DELETE FROM public.user_session
  WHERE telefone = target_phone;

  -- Step 1: Delete from sessao_agendamento
  DELETE FROM public.sessao_agendamento
  WHERE telefone = target_phone;

  -- Step 2: Delete from cliente
  DELETE FROM public.cliente
  WHERE telefone = target_phone;

END $$;
